// ============================================================
// Valida entrada e constrói prompt estruturado para o Match Predictor
// Input: { match_id, home_team, away_team, stage, stats (match_stats row),
//          news_context[], sentiment_context{} }
// ============================================================
const input = $input.first().json;

if (!input.match_id)  throw new Error('SWF-MatchPredictor: match_id obrigatório');
if (!input.home_team) throw new Error('SWF-MatchPredictor: home_team obrigatório');
if (!input.away_team) throw new Error('SWF-MatchPredictor: away_team obrigatório');

const s = input.stats || {};

// Formata forma recente como string legível
const formatForm = (arr) => Array.isArray(arr) && arr.length > 0 ? arr.join('') : 'N/A';

// Formata notícias de impacto
const newsLines = (input.news_context || []).slice(0, 5).map((n, i) =>
  `  [${i+1}] ${n.source} - Impact: ${n.impact_score?.toFixed(2)} - ${n.key_insight || n.title}`
).join('\n') || '  Sem notícias relevantes nas últimas 24h';

// Monta seção de sentimento
const sentHome = input.sentiment_context?.home || {};
const sentAway = input.sentiment_context?.away || {};
const sentLines = [
  `  ${input.home_team}: positivo=${(sentHome.positive_ratio||0).toFixed(2)}, negativo=${(sentHome.negative_ratio||0).toFixed(2)} (${sentHome.dominant_sentiment||'N/A'})`,
  `  ${input.away_team}: positivo=${(sentAway.positive_ratio||0).toFixed(2)}, negativo=${(sentAway.negative_ratio||0).toFixed(2)} (${sentAway.dominant_sentiment||'N/A'})`,
].join('\n');

const systemPrompt = `Você é um estatístico esportivo especializado em previsão de resultados de Copa do Mundo.
Analise os dados fornecidos e gere uma previsão probabilística fundamentada.
Retorne EXCLUSIVAMENTE um JSON válido. Não adicione texto, não use markdown.

{
  "home_win_prob": <0.000 a 1.000>,
  "draw_prob": <0.000 a 1.000>,
  "away_win_prob": <0.000 a 1.000>,
  "predicted_home_score": <integer 0-9>,
  "predicted_away_score": <integer 0-9>,
  "confidence": <0.00 a 1.00>,
  "key_factors": ["fator 1", "fator 2", "fator 3"],
  "risk_factors": ["risco 1", "risco 2"],
  "justification": "análise narrativa em 3-5 frases",
  "over_under_2_5": "over" ou "under",
  "both_teams_score": true ou false
}

REGRAS OBRIGATÓRIAS:
- home_win_prob + draw_prob + away_win_prob = 1.000 (exatamente)
- confidence < 0.40 se dados históricos insuficientes (< 3 jogos)
- confidence < 0.50 se lesões/suspensões críticas de titulares
- Justificativa deve citar ao menos 2 fatores quantitativos dos dados fornecidos
- NÃO fabricar estatísticas não presentes nos dados`;

const userContent = `PARTIDA: ${input.home_team} vs ${input.away_team}
FASE: ${input.stage || 'Copa do Mundo 2026'}
DATA: ${input.scheduled_at || 'N/A'}

FORMA RECENTE (últimos 5 jogos):
  ${input.home_team}: ${formatForm(s.home_form)} - ${s.home_form_pts || 0} pontos
  ${input.away_team}: ${formatForm(s.away_form)} - ${s.away_form_pts || 0} pontos

MÉDIAS DE GOLS:
  ${input.home_team}: ${s.home_goals_scored_avg?.toFixed(2) || 'N/A'} marcados / ${s.home_goals_conceded_avg?.toFixed(2) || 'N/A'} sofridos por jogo
  ${input.away_team}: ${s.away_goals_scored_avg?.toFixed(2) || 'N/A'} marcados / ${s.away_goals_conceded_avg?.toFixed(2) || 'N/A'} sofridos por jogo

HISTÓRICO HEAD-TO-HEAD (últimos 10 jogos):
  ${input.home_team} venceu: ${s.h2h_home_wins || 0} | Empates: ${s.h2h_draws || 0} | ${input.away_team} venceu: ${s.h2h_away_wins || 0}
  Média de gols: ${input.home_team} ${s.h2h_home_goals_avg?.toFixed(2) || 'N/A'} x ${s.h2h_away_goals_avg?.toFixed(2) || 'N/A'} ${input.away_team}

DESEMPENHO NA COPA 2026:
  ${input.home_team}: ${s.home_goals_in_tournament || 0} gols em ${s.home_matches_in_tournament || 0} jogos
  ${input.away_team}: ${s.away_goals_in_tournament || 0} gols em ${s.away_matches_in_tournament || 0} jogos

CONTEXTO DE LESÕES/SUSPENSÕES:
  ${input.home_team}: ${s.home_suspended_count || 0} suspensões, notícias de lesão: ${s.home_has_injury_news ? 'SIM' : 'NÃO'}
  ${input.away_team}: ${s.away_suspended_count || 0} suspensões, notícias de lesão: ${s.away_has_injury_news ? 'SIM' : 'NÃO'}

NOTÍCIAS RECENTES (últimas 24h, por impacto):
${newsLines}

SENTIMENTO PÚBLICO:
${sentLines}

Gere a previsão baseando-se nos dados acima.`;

return [{
  json: {
    match_id:    input.match_id,
    home_team:   input.home_team,
    away_team:   input.away_team,
    system_prompt: systemPrompt,
    user_content:  userContent,
    started_at:    new Date().toISOString(),
  }
}];

// ============================================================
// Parse e validação rigorosa da previsão do GPT
// ============================================================
const prepData  = $('Prepare Predictor Prompt').first().json;
const apiResult = $input.first().json;

const finishedAt   = new Date().toISOString();
const processingMs = new Date(finishedAt) - new Date(prepData.started_at);
const tokensUsed   = apiResult.usage?.total_tokens || 0;

const message = apiResult.choices?.[0]?.message?.content;
if (!message) {
  throw new Error(`GPT retornou vazio: ${JSON.stringify(apiResult.error || {})}`);
}

let parsed;
try {
  parsed = JSON.parse(message.replace(/```json\n?|```/g, '').trim());
} catch (e) {
  throw new Error(`Falha ao parsear JSON do Predictor: ${e.message}. Resposta: ${message.substring(0, 300)}`);
}

// Extrai e valida probabilidades
let homeP = parseFloat(parsed.home_win_prob);
let drawP = parseFloat(parsed.draw_prob);
let awayP = parseFloat(parsed.away_win_prob);

// Valida range individual
if (isNaN(homeP) || isNaN(drawP) || isNaN(awayP)) {
  throw new Error('Probabilidades inválidas (NaN) na resposta do GPT');
}
homeP = Math.max(0.001, Math.min(0.998, homeP));
drawP = Math.max(0.001, Math.min(0.998, drawP));
awayP = Math.max(0.001, Math.min(0.998, awayP));

// Renormaliza para somar exatamente 1.000
const total = homeP + drawP + awayP;
homeP = parseFloat((homeP / total).toFixed(3));
drawP = parseFloat((drawP / total).toFixed(3));
awayP = parseFloat((1.0 - homeP - drawP).toFixed(3)); // garante soma exata

// Ajuste final: evita floating point que cause violação da constraint
const checkSum = homeP + drawP + awayP;
if (Math.abs(checkSum - 1.0) > 0.004) {
  awayP = parseFloat((awayP + (1.0 - checkSum)).toFixed(3));
}

const confidence = Math.min(1, Math.max(0, parseFloat(parsed.confidence) || 0.5));
const predHome = Math.max(0, Math.min(9, parseInt(parsed.predicted_home_score) || 0));
const predAway = Math.max(0, Math.min(9, parseInt(parsed.predicted_away_score) || 0));

const validOU = ['over', 'under'];
const overUnder = validOU.includes(parsed.over_under_2_5) ? parsed.over_under_2_5 : null;

const justification = parsed.justification || '';
if (justification.length < 20) {
  throw new Error(`Justificativa insuficiente (${justification.length} chars)`);
}

return [{
  json: {
    match_id:              prepData.match_id,
    home_win_prob:         homeP,
    draw_prob:             drawP,
    away_win_prob:         awayP,
    predicted_home_score:  predHome,
    predicted_away_score:  predAway,
    confidence,
    key_factors:           parsed.key_factors || [],
    risk_factors:          parsed.risk_factors || [],
    justification,
    over_under_2_5:        overUnder,
    both_teams_score:      typeof parsed.both_teams_score === 'boolean' ? parsed.both_teams_score : null,
    raw_gpt_response:      parsed,
    // Auditoria
    ai_model:              apiResult.model || 'gpt-4o',
    prompt_version:        'v1.0',
    tokens_used:           tokensUsed,
    processing_ms:         processingMs,
    finished_at:           finishedAt,
  }
}];

const prepData = $('Prepare Predictor Prompt').first().json;
const error = $input.first().json;
const errorMsg = error.error?.message || JSON.stringify(error);
console.error(`[SWF-MatchPredictor] GPT error for match=${prepData.match_id}: ${errorMsg}`);
return [{ json: { gpt_error: true, match_id: prepData.match_id, error_message: errorMsg, processing_ms: new Date() - new Date(prepData.started_at) } }];
